var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"으아아, 전학 첫날부터 지각이다!","JPN":"うわぁ、転入初日から遅刻だぁ！","ENG":"Ahh, I'm late for my first day at the new school!","TWN":"哇啊啊，轉學第一天就遲到！"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"거기 학생. 잠시만요.","JPN":"そこの学生さん。待ってください。","ENG":"Excuse me. Do you have moment?","TWN":"那位同學！等一下。"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"네? 저요?","JPN":"はい？　私ですか？","ENG":"Hmm? Me?","TWN":"咦？我？"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"그래요. 학생, 혹시 운명에 관심 있으신가요?","JPN":"そうです。もしかして、運命に興味はありませんか？","ENG":"Yes. Are you perhaps interested in fate?","TWN":"就是妳，同學。妳對命運感興趣嗎？"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"우, 운명이요? 그런 건 생각해 본 적이 없는데.","JPN":"う、運命ですか？\\nそういうのはあまり考えた事ありません。","ENG":"F-fate? I've never even thought about that.","TWN":"命、命運？我從沒想過這種事耶。"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"한심하군요. 이 혼란의 시대를 살아가는 사람들은 항상 자신의 운명에 주의를 기울여야 하는 것입니다.","JPN":"情けないですね。この混乱の時代を生きている人々は、常に自身の運命に興味を持たなければなりません。","ENG":"How pitiful. Everyone living in this chaotic age must always be aware of their fate.","TWN":"太不像話了。生活在這個混亂時代的人們，必須要時刻關注自己的命運。"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"아하......","JPN":"へぇ……","ENG":"Aha...","TWN":"原來如此……"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"앗! 그런데 저 지금 지각이라서 나중에......!","JPN":"あっ！　でも今、遅刻しちゃってて！　また今度……！","ENG":"Ah! But I'm really late for school right now, so if we could continue later!","TWN":"啊！可是我快遲到了，所以之後再……！"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"지금 지각이 중요한 게 아니에요!","JPN":"今は遅刻が重要ではありません！","ENG":"School's not important right now!","TWN":"現在遲到並不重要！"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"찔끔......","JPN":"ビクッ……","ENG":"*Flinch*","TWN":"驚……"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"다시 보니 학생 얼굴에 맑은 기운이 가득하군요.","JPN":"よく見ると、学生さんの顔は清らかな気で満たされていますね。","ENG":"Upon a second look, I can tell that your face is filled with purity.","TWN":"仔細一看，同學妳的臉上散發著一種澄澈的氣場呢。"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"네? 맑은 기운이요? 그럼 좋은 거죠?!","JPN":"はい？　清らかな気？　それっていいことなんですか！？","ENG":"What? Purity? That's good, right?!","TWN":"嗯？澄澈的氣場？所以是好事嗎？"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"네, 하지만 사악한 엘카노의 암흑 에너지가 학생의 맑은 기운을 흐리고 있어요.","JPN":"はい、しかし邪悪なエルカノの暗黒エネルギーが清らかな気を濁らせてしまうのです。","ENG":"Yes, but the evil dark energy of Elcano is clouding your purity.","TWN":"沒錯。但是埃爾卡諾邪惡的黑暗力量遮蔽了同學的澄澈氣場。"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"이대로 두면 학생에겐 계속 불행한 일이 닥칠 겁니다.","JPN":"このままですと、学生さんに不幸なことが降りかかるでしょう。","ENG":"If left alone, you will continue to experience misfortune.","TWN":"如果繼續放任下去，妳會遇到各種不幸的事情。"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"여름 감기에 걸린다거나, 돌부리에 걸려 넘어진다거나......","JPN":"夏風邪にかかったり、石につまずいて転んだり……","ENG":"Such as catching a cold in the summer, tripping on a stone...","TWN":"像是在夏天感冒、被石頭絆倒……"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"학생! 평소에도 걱정거리 같은 게 많지 않았나요?","JPN":"もしかして、日頃から心配事が多くありませんでしたか？","ENG":"You! Aren't you always filled with worries in your life?","TWN":"這位同學！妳平時有很多煩惱吧？"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"아뇨. 별로 걱정 같은 건 없었는데......","JPN":"いえ、特に心配事はありませんでした……","ENG":"No. I don't really have any worries...","TWN":"不，我沒什麼煩惱……"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"하지만 아무 걱정 마세요. 오늘 여기서 당신이 저를 만난 건 삼생의 행운이라고 할 수 있죠.","JPN":"しかし、心配は無用です。今日ここで私に会えたのは一生に二度とない幸運と言えるでしょう。","ENG":"But do not fear. Meeting me here today is the blessing of three lifetimes for you.","TWN":"不過，妳什麼都不用擔心。今天妳在這裡遇到我，可以說是三生有幸。"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};